sql:
SELECT DISTINCT categories.category_name
FROM categories
JOIN articles ON categories.category_id = articles.category_id;

SELECT AVG(engagement_count) AS average_engagements
FROM (
  SELECT article_id, COUNT(engagement_id) AS engagement_count
  FROM article_engagement
  GROUP BY article_id
);

SELECT articles.title, stories.story_name
FROM articles
INNER JOIN stories ON articles.story_id = stories.story_id;

external_knowledge:
1. 'Thematic gardens' metaphorically represents different categories of articles;
2. 'Cultivate' symbolizes the publishing activity by the 'New York Times';
3. 'Blossoms' metaphorically represents articles;
4. 'Nurtured' implies the creation and publication of articles.

sql:
SELECT AVG(engagements)
FROM (
  SELECT COUNT(*) as engagements
  FROM article_engagement
  GROUP BY article_id
) as subquery;

